UPDATE tb_order_timeout_close_fail
SET status = 'PROCESSING'
WHERE id = #{id}
  AND status = 'INIT'
  AND fail_count = #{expectedFailCount}

UPDATE tb_order_timeout_close_fail
SET status = 'HANDLED',
    next_retry_time = NULL
WHERE id = #{id}
  AND status = 'PROCESSING'
  AND fail_count = #{expectedFailCount}
